mapper.select:
SELECT p.POST_ID AS postId, p.CATEGORY_ID AS categoryId, c.CATEGORY_CD AS categoryCd, c.CATEGORY_NAME AS categoryName, p.USER_ID AS userId, p.NICKNAME AS nickname, p.TITLE AS title, p.CONTENT AS content, p.IS_NOTICE AS isNotice, p.VIEW_COUNT AS viewCount, p.LIKE_COUNT AS likeCount, p.SCRAP_COUNT AS scrapCount, p.DELETED_YN AS deletedYn, p.CREATED_AT AS createdAt, p.CS_CATEGORY_ID AS csCategoryId, (SELECT COUNT(*) FROM COMMUNITY_COMMENT WHERE POST_ID = p.POST_ID AND DELETED_YN = 'N') AS commentCount, COUNT(*) OVER() AS totalCount FROM COMMUNITY_POST p JOIN COMMUNITY_CATEGORY c ON p.CATEGORY_ID = c.CATEGORY_ID WHERE p.DELETED_YN = 'N' AND c.DELETED_YN = 'N'
AND c.CATEGORY_CD = #{categoryCd}
AND p.CS_CATEGORY_ID = #{csCategoryId}
AND p.CS_CATEGORY_ID IN
#{id}
AND p.TITLE LIKE CONCAT('%', #{keyword}, '%')
AND p.CONTENT LIKE CONCAT('%', #{keyword}, '%')
AND p.NICKNAME LIKE CONCAT('%', #{keyword}, '%')
AND (p.TITLE LIKE CONCAT('%', #{keyword}, '%') OR p.CONTENT LIKE CONCAT('%', #{keyword}, '%'))
AND EXISTS ( SELECT 1 FROM COMMUNITY_POST_HASHTAG ph JOIN COMMUNITY_HASHTAG h ON ph.HASHTAG_ID = h.HASHTAG_ID WHERE ph.POST_ID = p.POST_ID AND h.TAG_NAME = #{hashtag} )
ORDER BY p.IS_NOTICE DESC, p.CREATED_AT DESC LIMIT #{pagination.size} OFFSET #{pagination.offset}

mapper.update:
UPDATE COMMUNITY_POST
SET
    TITLE       = '[삭제된 게시글]',
    CONTENT     = '[삭제된 게시글]',
    DELETED_YN  = 'Y',
    UPDATED_AT  = NOW(),
    UPDATED_BY  = #{userId}
WHERE POST_ID   = #{postId}
  AND USER_ID   = #{userId}
  AND DELETED_YN = 'N'
